import './../components/project.css';
import { Link, useParams } from 'react-router-dom';

class ProjectPage extends Component {
  state = {
    id: null,
    name: null,
  };

  componentDidMount() {
    let id = this.props.match.params.id;
    this.setState({
      id: id,
    });
  }

  render() {
      console.log(this.props)
